// ChatBox.js

import React, { useState, useEffect } from 'react';
import { useLocation } from 'react-router-dom'; // Import useLocation
import ImportDataSidebar from './ImportDataSidebar'; // Import ImportDataSidebar
import './ChatBox.css';

function ChatBox() {
  const location = useLocation(); // Access the location prop
  const credentials = location.state?.selectedCredential; // Get selected credentials from state

  const [userStory, setUserStory] = useState(''); // User input for the user story
  const [messages, setMessages] = useState([]); // Messages in the chat
  const [isSidebarVisible, setIsSidebarVisible] = useState(false); // To toggle sidebar visibility
  const [isProcessing, setIsProcessing] = useState(false); // To disable buttons while processing

  // If credentials are not passed, show an error message
  if (!credentials) {
    return <div>Error: No credentials found. Please go back and select credentials.</div>;
  }

  // Function to handle generating test cases based on the user story
  const generateTestCases = async (userStoryData) => {
    setIsProcessing(true); // Disable input while processing
    setMessages((prevMessages) => [
      ...prevMessages,
      { text: 'Generating test cases...', isUserMessage: false }
    ]);

    try {
      const response = await fetch(
        `https://localhost:7216/api/GenerateTestCases?domain=${credentials.domain}&project=${credentials.project}&issueType=${credentials.issueType}&userStory=${userStoryData}`
      );
      const data = await response.json();
      
      if (data && data.testCases) {
        setMessages((prevMessages) => [
          ...prevMessages,
          { text: 'Test cases generated successfully!', isUserMessage: false },
          ...data.testCases.map((testCase, index) => ({
            text: `${index + 1}. ${testCase.description}`,
            isUserMessage: false
          }))
        ]);
      } else {
        setMessages((prevMessages) => [
          ...prevMessages,
          { text: 'No test cases generated.', isUserMessage: false }
        ]);
      }
    } catch (error) {
      setMessages((prevMessages) => [
        ...prevMessages,
        { text: 'Error generating test cases: ' + error.message, isUserMessage: false }
      ]);
    } finally {
      setIsProcessing(false); // Enable input after processing
    }
  };

  // Function to handle sending a user message
  const handleSendMessage = () => {
    if (!userStory.trim()) return;

    // Add the user input to the messages
    setMessages((prevMessages) => [
      ...prevMessages,
      { text: userStory, isUserMessage: true }
    ]);

    // Generate test cases based on the user story input
    generateTestCases(userStory);
    setUserStory(''); // Clear the input field after sending
  };

  // Function to toggle the sidebar visibility
  const toggleSidebar = () => {
    setIsSidebarVisible(!isSidebarVisible);
  };

  return (
    <div className="chatbox-container">
      <div className="chat-container">
        <div className="chat-box">
          <div className="chat-box-messages">
            {messages.map((message, index) => (
              <div key={index} className={message.isUserMessage ? 'user' : 'bot'}>
                {message.text}
              </div>
            ))}
          </div>
          <div className="chat-input-container">
            <textarea
              value={userStory}
              onChange={(e) => setUserStory(e.target.value)}
              placeholder="Type your user story"
              rows="6"
              disabled={isProcessing} // Disable input while processing
            />
            <button onClick={handleSendMessage} disabled={isProcessing || !userStory.trim()}>
              Send
            </button>
          </div>
        </div>
      </div>

      <button className="import-button" onClick={toggleSidebar}>
        &#x2190;
      </button>

      {isSidebarVisible && (
        <ImportDataSidebar credentials={credentials} />
      )}
    </div>
  );
}

export default ChatBox;
